input.command:
ssh -o ConnectTimeout=10 cerebro 'bash -lc "
echo ===auth-creds===;
ls -la ~/.claude/.credentials.json 2>/dev/null && echo \"(credentials file present)\" || echo \"(no ~/.claude/.credentials.json)\";
ls -la ~/.claude.json 2>/dev/null | sed \"s/ bhyslop bhyslop//\" || echo \"(no ~/.claude.json)\";
echo ===mcp-config-in-repo===;
ls -la ~/projects/rbm_alpha_recipemuster/.mcp.json 2>/dev/null || echo \"(no repo .mcp.json)\";
echo ===vvx-binary===;
ls -la ~/projects/rbm_alpha_recipemuster/Tools/vvk/bin/vvx 2>/dev/null || echo \"(no vvx binary)\";
echo ===mcpServers-keys-in-userconfig===;
grep -o \\\"mcpServers\\\" ~/.claude.json 2>/dev/null | head -1 || true
"' 2>&1
